  "arborg.C.list.18.occupation": "Ekonomista",
  "arborg.C.list.19.occupation": "Student",
  "arborg.C.list.2.bio": "Guðný Björk Pálmadóttir jest projektantką i inżynierem innowacji i zajmuje 2. miejsce na liście Viðreisn w Árborg w wyborach samorządowych 2026. To pierwszy raz, gdy Viðreisn startuje w wyborach do rady miejskiej w Árborg.",
  "arborg.C.list.2.occupation": "Projektantka i inżynier innowacji",
  "arborg.C.list.20.occupation": "Dyrektor działu",
  "arborg.C.list.21.occupation": "Pielęgniarka",
  "arborg.C.list.22.occupation": "Dyrektor zarządzający",
  "arborg.C.list.3.bio": "Þorsteinn Haukur Harðarson jest doradcą i zajmuje 3. miejsce na liście Viðreisn w Árborg w wyborach samorządowych 2026, w których partia startuje po raz pierwszy w wyborach do rady miejskiej.",
  "arborg.C.list.3.occupation": "Doradca",
  "arborg.C.list.4.bio": "Birgir Marteinsson jest prawnikiem i zajmuje 4. miejsce na liście Viðreisn w Árborg w wyborach samorządowych 2026. Wnosi do listy wyborczej wiedzę prawniczą i wspiera konstruktywne cele Viðreisn w gminie.",
  "arborg.C.list.4.occupation": "Prawnik",
  "arborg.C.list.5.bio": "Ingunn Guðmundsdóttir jest ekonomistką i zajmuje 5. miejsce na liście Viðreisn w Árborg w wyborach samorządowych 2026. Wnosi wiedzę z zakresu spraw biznesowych i finansowych na rzecz gminy.",
  "arborg.C.list.5.occupation": "Ekonomistka",
  "arborg.C.list.6.occupation": "Kierownik zespołu",
  "arborg.C.list.7.occupation": "Kierowniczka placówki",
  "arborg.C.list.8.occupation": "Inżynier elektroenergetyk",
  "arborg.C.list.9.occupation": "Doradca",
  "arborg.C.tagline": "Viðreisn w Árborg — innowacje i profesjonalne zarządzanie",
  "arborg.D.agenda.0.text": "Árborg jako społeczność przyjazna rodzinie, w której dzieci, rodzice i starsi mieszkańcy korzystają z silnych usług i możliwości.",
  "arborg.D.agenda.0.title": "Społeczność przyjazna rodzinie",
  "arborg.D.agenda.1.text": "Rozsądna zabudowa i planowanie przestrzenne, które uwzględniają mieszkańców oraz przyszły rozwój gminy.",
  "arborg.D.agenda.1.title": "Planowanie przestrzenne",
  "arborg.D.agenda.2.text": "Innowacje i przedsiębiorczość wzmacniające zróżnicowane życie gospodarcze w rejonie Selfoss.",
  "arborg.D.agenda.2.title": "Innowacje",
  "arborg.D.agenda.3.text": "Odpowiedzialne zarządzanie finansami — zmniejszanie zadłużenia i lepsza sytuacja finansowa dają większą przestrzeń na świadczenie usług.",
  "arborg.D.agenda.3.title": "Odpowiedzialne finanse",
  "arborg.D.agenda.4.text": "Silna polityka zdrowia publicznego z naciskiem na sport i rekreację, aktywność fizyczną oraz profilaktykę.",
  "arborg.D.agenda.4.title": "Zdrowie publiczne",
  "arborg.D.agenda.5.text": "Zapewnienie seniorom wysokiej jakości usług, szacunku i dobrego życia — Árborg ma być dobrą społecznością na każdym etapie życia.",
  "arborg.D.agenda.5.title": "Dobre starzenie się",
  "arborg.D.list.1.bio": "Bragi Bjarnason urodził się 25 kwietnia 1981 roku i jest specjalistą w dziedzinie nauk o sporcie z tytułem MBA uzyskanym na Háskóla Íslands (2020). Pracuje dla Árborg od 18 lat, m.in. jako kierownik wydziału sportu i rekreacji, a 1 czerwca 2024 roku został burmistrzem. Pod jego przywództwem wynik operacyjny miasta znacznie się poprawił — z deficytu w wysokości 3,4 miliarda koron do nadwyżki około 500 milionów koron. Stoi na czele listy D Sjálfstæðisflokksins w Árborg.",
  "arborg.D.list.1.interests.0": "Równowaga finansowa i zmniejszanie zadłużenia",
  "arborg.D.list.1.interests.1": "Rozbudowa szkół i edukacja",
  "arborg.D.list.1.interests.2": "Niższe opłaty, gdy to możliwe",
  "arborg.D.list.1.interests.3": "Rekreacja i sport",
  "arborg.D.list.1.interests.4": "Miasto przyjazne rodzinie",
  "arborg.D.list.1.occupation": "Burmistrz",
  "arborg.D.list.10.occupation": "Prawnik",
  "arborg.D.list.11.occupation": "Lekarz",
  "arborg.D.list.12.occupation": "Specjalista ds. kadr i płac",
  "arborg.D.list.13.occupation": "Wulkanolog",
  "arborg.D.list.14.occupation": "Pracownik socjalny",
  "arborg.D.list.15.occupation": "Pracownik obsługi klienta",
