  "fjardabyggd.S.agenda.0.text": "Silne usługi socjalne i opieka zdrowotna dla wszystkich mieszkańców Fjarðabyggð.",
  "fjardabyggd.S.agenda.0.title": "Dobrobyt",
  "fjardabyggd.S.agenda.1.text": "Równe szanse i sprawiedliwość społeczna jako podstawa polityki.",
