  "gardabaer.M.list.21.occupation": "były dyrektor techniczny Kringlerinnar",
  "gardabaer.M.list.22.occupation": "poseł",
  "gardabaer.M.list.3.bio": "Snorri Marteinsson jest dyrektorem finansowym i pracuje jako kierownik w Wells Fargo Securities. Zajmuje 3. miejsce na liście M Miðflokkurinn w Garðabær, a także zajmował 3. miejsce na liście partii w 2022 roku.",
  "gardabaer.M.list.3.occupation": "Dyrektor finansowy",
  "gardabaer.M.list.4.bio": "Bessí Þóra Jónsdóttir jest ekonomistką i zajmuje 4. miejsce na liście M Miðflokkurinn w Garðabær w wyborach samorządowych 2026.",
  "gardabaer.M.list.4.occupation": "Ekonomista",
  "gardabaer.M.list.5.bio": "Unnur Ýr Jónsdóttir jest stewardesą i zajmuje 5. miejsce na liście M Miðflokkurinn w Garðabær w wyborach samorządowych 2026.",
  "gardabaer.M.list.5.occupation": "Stewardesa",
  "gardabaer.M.list.6.occupation": "Specjalista ds. biznesu",
