  "hafnarfjordur.S.list.1.interests.4": "Sprawy europejskie i współpraca międzynarodowa",
  "hafnarfjordur.S.list.1.occupation": "Radny miejski, wiceprzewodniczący Samfylkingin",
  "hafnarfjordur.S.list.10.occupation": "Politolog",
  "hafnarfjordur.S.list.11.occupation": "Dyrektor zarządzający",
  "hafnarfjordur.S.list.12.occupation": "Nadzór i zarządzanie projektami w VSR",
