  "hunabyggd.B.agenda.0.text": "Postęp i rozwój na Vesturlandi.",
  "hunabyggd.B.agenda.0.title": "Postęp",
  "hunabyggd.B.agenda.1.text": "Silna opieka zdrowotna i usługi socjalne.",
  "hunabyggd.B.agenda.1.title": "Opieka zdrowotna",
  "hunabyggd.B.agenda.2.text": "Wspieranie rolników i rozwoju obszarów wiejskich.",
  "hunabyggd.B.agenda.2.title": "Rolnictwo",
  "hunabyggd.B.list.1.bio": "Grímur Rúnar Lárusson jest prawnikiem w Blönduósi i stoi na czele listy B Framsókn i zwolenników postępu w Húnabyggð w wyborach 2026. Pełni funkcję wiceprzewodniczącego rady gminy Húnabyggð oraz przewodniczącego komisji ds. sportu, rekreacji i zdrowia publicznego. Opisuje swoją 18-osobową listę jako połączenie doświadczenia, ambicji i zaangażowania na rzecz społeczności.",
  "hunabyggd.B.list.1.interests.0": "Postęp i rozwój",
  "hunabyggd.B.list.1.interests.1": "Sport, rekreacja i zdrowie publiczne",
  "hunabyggd.B.list.1.interests.2": "Opieka zdrowotna i usługi socjalne",
  "hunabyggd.B.list.1.interests.3": "Rolnictwo i rozwój obszarów wiejskich",
  "hunabyggd.B.list.1.occupation": "Prawnik",
  "hunabyggd.B.list.2.occupation": "Kandydat",
  "hunabyggd.B.tagline": "Framsókn i zwolennicy postępu w Húnabyggð",
  "hunabyggd.D.agenda.0.text": "Silny rozwój infrastruktury i gospodarki.",
  "hunabyggd.D.agenda.0.title": "Rozwój",
  "hunabyggd.D.agenda.1.text": "Wspieranie działalności gospodarczej i innowacji.",
  "hunabyggd.D.agenda.1.title": "Gospodarka",
  "hunabyggd.D.agenda.2.text": "Przejrzyste i skuteczne zarządzanie.",
  "hunabyggd.D.agenda.2.title": "Zarządzanie",
  "hunabyggd.D.list.1.bio": "Guðmundur Haukur Jakobsson jest mistrzem instalacji wodno-kanalizacyjnych i dyrektorem zarządzającym oraz pełni funkcję przewodniczącego rady gminy Húnabyggð od utworzenia gminy w 2022 roku. Wcześniej był przewodniczącym rady gminy Blönduósbær. Jego lista D uzyskała 37,7% głosów i 4 z 9 mandatów w 2022 roku. W 2026 roku ponownie staje na czele Sjálfstæðismenn i niezależnych i opisuje listę jako „kompetentnych ludzi z miast i obszarów wiejskich, w każdym wieku, o zróżnicowanym doświadczeniu”.",
  "hunabyggd.D.list.1.interests.0": "Rozwój infrastruktury i gospodarki",
  "hunabyggd.D.list.1.interests.1": "Przejrzyste i skuteczne zarządzanie",
  "hunabyggd.D.list.1.interests.2": "Linie przesyłowe energii elektrycznej i kwestie energetyczne",
  "hunabyggd.D.list.1.interests.3": "Odpowiedzialność społeczna i innowacje",
  "hunabyggd.D.list.1.occupation": "Mistrz instalacji wodno-kanalizacyjnych i dyrektor zarządzający",
  "hunabyggd.D.list.2.occupation": "Kandydat",
  "hunabyggd.D.tagline": "Sjálfstæðismenn i niezależni w Húnabyggð",
  "hunabyggd.HBA.agenda.0.text": "Współpraca wszystkich mieszkańców na rzecz rozwoju gminy.",
  "hunabyggd.HBA.agenda.0.title": "Współpraca",
