  "kjosarhreppur.KJA.agenda.0.text": "Ochrona Kjós i zrównoważony rozwój w jednym z najpiękniejszych obszarów kraju.",
  "kjosarhreppur.KJA.agenda.0.title": "Ochrona przyrody",
  "kjosarhreppur.KJA.agenda.1.text": "Poprawa warunków zamieszkania i infrastruktury w celu wzmocnienia osadnictwa w gminie.",
  "kjosarhreppur.KJA.agenda.1.title": "Osadnictwo",
  "kjosarhreppur.KJA.agenda.2.text": "Wzmacnianie więzi społecznych i udziału mieszkańców w zarządzaniu.",
  "kjosarhreppur.KJA.agenda.2.title": "Społeczność",
  "kjosarhreppur.KJA.list.1.bio": "Sigurður Gunnar Sigurðsson zajmuje 1. miejsce na liście wyborczej KJA w Kjósarhreppur w wyborach samorządowych w 2026 roku.",
  "kjosarhreppur.KJA.list.1.occupation": "Wójt gminy i rolnik",
