  "mulathing.D.list.2.occupation": "Prawnik, wiceprzewodniczący Krajowego Związku Klubów Jeździeckich",
  "mulathing.D.list.20.occupation": "Księgowy",
  "mulathing.D.list.21.occupation": "Mechanik samochodowy, przewodniczący stowarzyszenia Sjálfstæðisflokkurinn w Djúpavogur",
