  "reykjanesbaer.B.list.14.occupation": "Wicedyrektor szkoły Stapaskóli",
  "reykjanesbaer.B.list.15.occupation": "Psycholog w HSS",
  "reykjanesbaer.B.list.16.occupation": "Kierowniczka pionu ds. rodziny",
  "reykjanesbaer.B.list.17.occupation": "Kierownik działu",
  "reykjanesbaer.B.list.18.occupation": "Specjalista ds. marketingu",
  "reykjanesbaer.B.list.19.occupation": "Uczeń szkoły średniej",
  "reykjanesbaer.B.list.2.bio": "Róbert Jóhann Guðmundsson jest mistrzem malarskim i współwłaścicielem Málningarþjónustu JRJ ehf., którą założył w 2004 roku. Urodził się i wychował w Keflavík, a od 2001 roku mieszka w Njarðvík. Przez cztery lata pełnił funkcję przedstawiciela Framsókn w radzie ds. środowiska i planowania przestrzennego Reykjanesbæjar oraz zasiada w zarządzie Húsasmíðameistara Suðurnesja.",
  "reykjanesbaer.B.list.2.occupation": "Radny miejski i mistrz malarski",
  "reykjanesbaer.B.list.20.occupation": "Prawnik",
  "reykjanesbaer.B.list.21.occupation": "Były radny miejski",
  "reykjanesbaer.B.list.22.occupation": "Zastępca posła",
  "reykjanesbaer.B.list.3.bio": "Díana Hilmarsdóttir jest kierowniczką Bjargarinnar, centrum zdrowia psychicznego Suðurnes w Reykjanesbæ. Posiada tytuł licencjata z pracy socjalnej uzyskany na Háskóla Íslands i zasiada jako radna miejska z ramienia Framsókn w radzie miejskiej Reykjanesbæjar.",
  "reykjanesbaer.B.list.3.occupation": "Radna miejska i kierowniczka Bjargarinnar",
  "reykjanesbaer.B.list.4.bio": "Birgir Már Bragasson jest dyrektorem zarządzającym Keflavíkur, stowarzyszenia sportowo-młodzieżowego (ÍUK). Zajmuje czwarte miejsce na liście kandydatów Framsókn w Reykjanesbæ w wyborach samorządowych 2026.",
  "reykjanesbaer.B.list.4.occupation": "Dyrektor zarządzający",
  "reykjanesbaer.B.list.5.occupation": "Specjalista",
  "reykjanesbaer.B.list.6.occupation": "Informatyk i pracownik mediów",
  "reykjanesbaer.B.list.7.occupation": "Kierownik projektu nadzoru przeciwpożarowego w BS",
  "reykjanesbaer.B.list.8.occupation": "Kierownik działu w Veitum",
  "reykjanesbaer.B.list.9.occupation": "Student uczelni wyższej i instruktor",
  "reykjanesbaer.B.tagline": "Halldóra Fríða stoi na czele Framsókn w Reykjanesbær",
  "reykjanesbaer.C.agenda.0.text": "Jasna wizja przyszłości i postępowe podejście do rozwoju Reykjanesbæ.",
  "reykjanesbaer.C.agenda.0.title": "Wizja przyszłości",
  "reykjanesbaer.C.agenda.1.text": "Silna i zróżnicowana gospodarka na Suðurnesjum — Bítlabærinn, gdzie pomysły stają się rzeczywistością.",
  "reykjanesbaer.C.agenda.1.title": "Gospodarka",
  "reykjanesbaer.C.agenda.2.text": "Planowanie i rozwój z myślą o mieszkańcach — miasto, w którym chcemy żyć.",
  "reykjanesbaer.C.agenda.2.title": "Planowanie",
  "reykjanesbaer.C.agenda.3.text": "Zrównoważony rozwój i odpowiedzialność środowiskowa we wszystkich działaniach strategicznych.",
  "reykjanesbaer.C.agenda.3.title": "Zrównoważony rozwój",
  "reykjanesbaer.C.agenda.4.text": "Wysokiej jakości edukacja i silne wsparcie szkolne jako podstawa dobrze prosperującego narodu.",
  "reykjanesbaer.C.agenda.4.title": "Edukacja",
  "reykjanesbaer.C.agenda.5.text": "Życie kulturalne i sektory kreatywne jako część tożsamości miasta.",
  "reykjanesbaer.C.agenda.5.title": "Kultura",
  "reykjanesbaer.C.list.1.bio": "Arnar Páll Guðmundsson jest ekonomistą i doradcą ds. zasobów ludzkich. Był przewodniczącym Viðreisn na Suðurnesjum i stoi na czele pierwszej w historii listy Viðreisn, która kiedykolwiek wystartowała w wyborach samorządowych w Reykjanesbæ w 2026 roku. Publikował artykuły o gospodarce i sprawach wyborczych na Vísir.",
  "reykjanesbaer.C.list.1.interests.0": "Różnorodność gospodarcza i rozwój rynku pracy",
  "reykjanesbaer.C.list.1.interests.1": "Reforma administracji publicznej i przejrzystość",
  "reykjanesbaer.C.list.1.interests.2": "Zasoby ludzkie i rynek pracy",
  "reykjanesbaer.C.list.1.interests.3": "Włączenie społeczne i dobrobyt",
  "reykjanesbaer.C.list.1.interests.4": "Wartości liberalne",
  "reykjanesbaer.C.list.1.occupation": "Ekonomista i doradca ds. zasobów ludzkich",
  "reykjanesbaer.C.list.10.occupation": "Wychowawca klasy",
  "reykjanesbaer.C.list.11.occupation": "Kierownik projektu",
  "reykjanesbaer.C.list.12.occupation": "Kierownik sklepu",
