  "reykjanesbaer.M.list.22.occupation": "honorowy członek Miðflokksins",
  "reykjanesbaer.M.list.3.bio": "Sigrún Þorsteinsdóttir jest pracownikiem obsługi i opiekunem społecznym. Zajmuje trzecie miejsce na liście wyborczej Miðflokksins w Reykjanesbæ w 2026 roku.",
  "reykjanesbaer.M.list.3.occupation": "Pracownik obsługi i opiekun społeczny",
  "reykjanesbaer.M.list.4.bio": "Bjarni Gunnólfsson jest z wykształcenia kucharzem. Zajmuje czwarte miejsce na liście wyborczej Miðflokksins w Reykjanesbæ w 2026 roku.",
  "reykjanesbaer.M.list.4.occupation": "Kucharz",
  "reykjanesbaer.M.list.5.bio": "Matthildur Júlía Matthíasdóttir jest opiekunem i zajmuje piąte miejsce na liście wyborczej Miðflokksins w Reykjanesbæ w 2026 roku.",
  "reykjanesbaer.M.list.5.occupation": "Opiekun",
