  "reykjavik.B.list.31.occupation": "Chemik",
  "reykjavik.B.list.32.occupation": "Kierowca autobusu miejskiego",
  "reykjavik.B.list.33.occupation": "Kierownik działu szkolnego",
  "reykjavik.B.list.34.occupation": "Student, pracownik ds. obsługi szkolnej",
  "reykjavik.B.list.35.occupation": "Przewodniczący seniorów w Fossvogi",
