  "reykjavik.D.list.8.occupation": "Autor, wydawca",
  "reykjavik.D.list.9.occupation": "Dyrektor zarządzający",
  "reykjavik.D.tagline": "Reykjavík potrzebuje zmian",
  "reykjavik.F.agenda.0.text": "Społeczeństwo, w którym wszyscy mogą żyć z godnością, bezpieczeństwem i równymi szansami; „jakość życia nie jest wyłącznym przywilejem nielicznych”.",
  "reykjavik.F.agenda.0.title": "Ludzie na pierwszym miejscu",
  "reykjavik.F.agenda.1.text": "Rozwój przystępnych cenowo mieszkań i małych lokali we współpracy z instytucjami społecznymi; sprzeciw wobec nadmiernego zagęszczania zabudowy.",
  "reykjavik.F.agenda.1.title": "Przystępne cenowo mieszkania",
  "reykjavik.F.agenda.2.text": "Znaczne skrócenie list oczekujących; zbadanie bardziej zróżnicowanych i opłacalnych sposobów zwiększenia liczby miejsc w przedszkolach.",
  "reykjavik.F.agenda.2.title": "Sprawy przedszkoli",
  "reykjavik.F.agenda.3.text": "Poprawa płynności transportu dla wszystkich środków przemieszczania się; system musi działać dla tych, którzy są zależni od samochodów.",
  "reykjavik.F.agenda.3.title": "Sprawiedliwość transportowa",
  "reykjavik.F.agenda.4.text": "Nacisk na jakość edukacji, poprawę nauki czytania, zindywidualizowane wsparcie i dobrostan uczniów.",
  "reykjavik.F.agenda.4.title": "Szkoły podstawowe",
  "reykjavik.F.agenda.5.text": "Zapewnienie spokojnych późniejszych lat życia i godności na starość.",
  "reykjavik.F.agenda.5.title": "Usługi dla seniorów",
  "reykjavik.F.list.1.bio": "Guðmundur Ingi Þóroddsson urodził się w 1974 roku i jest przewodniczącym Afstaða, stowarzyszenia więźniów i byłych więźniów. Łącznie spędził w więzieniu 16 lat, a od tego czasu poświęcił się walce o prawa więźniów. Pracuje w Wydziale Opieki Społecznej miasta Reykjavík i stoi na czele listy Flokkur fólksins w Reykjavík.",
  "reykjavik.F.list.1.interests.0": "Prawa więźniów i resocjalizacja",
  "reykjavik.F.list.1.interests.1": "Usługi społeczne i osoby bezdomne",
  "reykjavik.F.list.1.interests.2": "Równość w systemie prawnym",
  "reykjavik.F.list.1.occupation": "Przewodniczący Afstaða, działacz na rzecz praw więźniów i dobrobytu społecznego",
  "reykjavik.F.list.10.occupation": "Dyrektor biura klubu parlamentarnego Flokk fólksins",
  "reykjavik.F.list.11.occupation": "Trener piłki nożnej",
  "reykjavik.F.list.12.occupation": "Drukarz",
  "reykjavik.F.list.13.occupation": "Sekretarka medyczna",
  "reykjavik.F.list.14.occupation": "Pracownik przedszkola",
  "reykjavik.F.list.15.occupation": "Nauczyciel sztuki",
  "reykjavik.F.list.16.occupation": "Inżynier techniczny",
  "reykjavik.F.list.17.occupation": "Informatyk",
  "reykjavik.F.list.18.occupation": "Pracownik biurowy",
  "reykjavik.F.list.19.occupation": "Strażnicy sprzętu",
  "reykjavik.F.list.2.bio": "Einar Sveinbjörn Guðmundsson jest inżynierem systemowym i pełnił funkcję zastępcy radnego miejskiego Flokkur fólksins w radzie miejskiej Reykjavík. Jest jednym z najbardziej doświadczonych kandydatów partii w mieście.",
  "reykjavik.F.list.2.interests.0": "Usługi cyfrowe",
  "reykjavik.F.list.2.interests.1": "Dobrobyt i prawa mieszkańców",
  "reykjavik.F.list.2.interests.2": "Przejrzystość zarządzania",
  "reykjavik.F.list.2.occupation": "Inżynier systemowy, zastępca radnego miejskiego",
