  "reykjavik.F.list.9.occupation": "Przedsiębiorca, założyciel Flow",
  "reykjavik.F.tagline": "Ludzie na pierwszym miejscu",
  "reykjavik.G.agenda.0.text": "Uprościć strukturę miasta, usprawnić funkcjonowanie i ograniczyć narastanie zadłużenia.",
  "reykjavik.G.agenda.0.title": "Planowanie i funkcjonowanie",
  "reykjavik.G.agenda.1.text": "Szczególny nacisk na bezpieczeństwo działania i rzetelne metody administracyjne.",
  "reykjavik.G.agenda.1.title": "Bezpieczeństwo operacyjne",
  "reykjavik.G.agenda.2.text": "Słuchać mieszkańców miasta — regularne badania opinii i lepszy kontakt z mieszkańcami.",
  "reykjavik.G.agenda.2.title": "Konsultacje z mieszkańcami",
  "reykjavik.G.agenda.3.text": "Sprzeciw wobec pierwotnego planu Borgarlína; poparcie dla Sundagang (tunel zamiast mostu).",
  "reykjavik.G.agenda.3.title": "Transport",
  "reykjavik.G.list.1.bio": "Ingimar Þór Friðriksson jest przedsiębiorcą i informatykiem. Ukończył studia licencjackie z informatyki na Háskóli Íslands w 1989 roku oraz studia MBA na Háskólanum í Reykjavík w 2002 roku. W latach 2011–2025 pracował jako kierownik działu informatyki gminy Kópavogur, a obecnie stoi na czele komitetu wyborczego Góðan daginn.",
  "reykjavik.G.list.1.interests.0": "Efektywność funkcjonowania miasta",
  "reykjavik.G.list.1.interests.1": "Przegląd tras autobusowych",
  "reykjavik.G.list.1.interests.2": "Kwestie parkingowe",
  "reykjavik.G.list.1.occupation": "Dyrektor zarządzający",
  "reykjavik.G.list.10.occupation": "Informatyk",
  "reykjavik.G.list.11.occupation": "Nauczyciel matematyki i inżynier",
  "reykjavik.G.list.12.occupation": "Student medycyny",
  "reykjavik.G.list.13.occupation": "Cieśla",
  "reykjavik.G.list.14.occupation": "Mistrz stolarstwa meblowego",
  "reykjavik.G.list.15.occupation": "Technolog",
