  "reykjavik.J.list.29.occupation": "Muzyk",
  "reykjavik.J.list.3.bio": "Hannes Pétursson jest pracownikiem handlu i zajmuje 3. miejsce na liście J (Sósíalistaflokks Íslands) w wyborach samorządowych w Reykjavík w 2026 roku.",
  "reykjavik.J.list.3.occupation": "Pracownik handlu",
  "reykjavik.J.list.30.occupation": "Mistrz elektryk",
