  "reykjavik.J.list.38.occupation": "Kierownik projektów i jakości",
  "reykjavik.J.list.39.occupation": "Osoba z niepełnosprawnością",
  "reykjavik.J.list.4.bio": "Geirdís Hanna Kristjánsdóttir urodziła się i wychowała w Siglufirði. Od 2008 roku pobiera rentę z tytułu niezdolności do pracy, ale starała się uczestniczyć w rynku pracy na tyle, na ile mogła. Zasiada w zarządzie sekcji bowlingowej ÍR i KLÍ.",
  "reykjavik.J.list.4.interests.0": "Prawa osób z niepełnosprawnościami i rencistów",
  "reykjavik.J.list.4.interests.1": "Mieszkalnictwo",
