  "skagafjordur.D.tagline": "Partia Niepodległości w Skagafjörður — stabilność i postęp",
  "skagafjordur.M.agenda.0.text": "Odpowiedzialne zarządzanie finansami i dyscyplina w działalności; spłata długów, większa przejrzystość i jasne priorytety.",
  "skagafjordur.M.agenda.0.title": "Odpowiedzialne finanse",
  "skagafjordur.M.agenda.1.text": "Podwyższenie świadczeń za opiekę domową do czasu uzyskania miejsca w przedszkolu, elastyczne opcje płatności i poprawa warunków pracy nauczycieli przedszkolnych.",
  "skagafjordur.M.agenda.1.title": "Sprawy przedszkolne",
  "skagafjordur.M.agenda.2.text": "Silne szkolnictwo i działalność sportowa; obiekty sportowe w Hofsósi i Sauðárkróki; profesjonalizm w nauczaniu i wsparcie dla dzieci ze specjalnymi potrzebami.",
  "skagafjordur.M.agenda.2.title": "Szkoły podstawowe i działalność sportowa",
  "skagafjordur.M.agenda.3.text": "Modernizacja systemu kanalizacyjnego, zwiększenie wykorzystania energii geotermalnej, poprawa utrzymania dróg i odśnieżania oraz usprawnienie odbioru odpadów.",
  "skagafjordur.M.agenda.3.title": "Infrastruktura i podstawowe usługi",
  "skagafjordur.M.agenda.4.text": "Wsparcie dla rybołówstwa, rolnictwa, produkcji żywności, turystyki i przemysłu; współpraca z Hóla háskóla.",
  "skagafjordur.M.agenda.4.title": "Rozwój gospodarczy",
  "skagafjordur.M.agenda.5.text": "Rozwój domu opieki, poprawa usług dla osób starszych i z niepełnosprawnościami oraz walka z dyskryminacją — usługi mają obejmować wszystkich mieszkańców.",
  "skagafjordur.M.agenda.5.title": "Dobrobyt i usługi",
  "skagafjordur.M.list.1.occupation": "rolnik i mechanik",
  "skagafjordur.M.list.10.occupation": "mechanik",
  "skagafjordur.M.list.11.occupation": "rolnik",
