  "thingeyjarsveit.THVL.agenda.0.text": "Wzmacnianie zróżnicowanego rynku pracy i innowacji w Þingeyjarsveit.",
  "thingeyjarsveit.THVL.agenda.0.title": "Zatrudnienie",
  "thingeyjarsveit.THVL.agenda.1.text": "Zapewnienie opieki zdrowotnej obejmującej wszystkie części gminy.",
