  "vestmannaeyjar.D.list.8.occupation": "Kierowca",
  "vestmannaeyjar.D.list.9.occupation": "Pracownik domu mieszkalnego z opieką",
  "vestmannaeyjar.D.tagline": "Eyþór Harðarson stoi na czele Sjálfstæðisflokkurinn w Vestmannaeyjum",
  "vestmannaeyjar.E.agenda.0.text": "Dokończenie budowy nowego wodociągu — najpilniejsze zadanie dla mieszkańców wysp.",
  "vestmannaeyjar.E.agenda.0.title": "Wodociąg",
  "vestmannaeyjar.E.agenda.1.text": "Lepszy transport do i z wysp — Landeyjahöfn i połączenia lotnicze.",
  "vestmannaeyjar.E.agenda.1.title": "Transport",
  "vestmannaeyjar.E.agenda.2.text": "Zapewnienie miejsc w przedszkolu i wysokiej jakości usług dla małych dzieci.",
  "vestmannaeyjar.E.agenda.2.title": "Przedszkole",
  "vestmannaeyjar.E.agenda.3.text": "Silne szkoły podstawowe, w których dzieci otrzymują najlepszą możliwą edukację.",
  "vestmannaeyjar.E.agenda.3.title": "Szkoły podstawowe",
  "vestmannaeyjar.E.agenda.4.text": "Rozbudowa i modernizacja obiektów sportowych na wyspach.",
  "vestmannaeyjar.E.agenda.4.title": "Obiekty sportowe",
  "vestmannaeyjar.E.agenda.5.text": "Rozwój i ożywienie centrum miasta jako zadbanego miejsca spotkań.",
  "vestmannaeyjar.E.agenda.5.title": "Centrum miasta",
  "vestmannaeyjar.E.list.1.bio": "Arndís María Kjartansdóttir jest nauczycielką oraz licencjonowaną pośredniczką w obrocie nieruchomościami, przedsiębiorstwami i statkami, prowadzącą własną firmę zajmującą się sprzedażą nieruchomości i działalnością handlową. Studiuje również na studiach magisterskich z psychologii pozytywnej na Háskóla Íslands. Stoi na czele Eyjalistinn w Vestmannaeyjum 2026 — niezależnej listy, w której sprawy ważne dla wysp zawsze są na pierwszym planie.",
  "vestmannaeyjar.E.list.1.interests.0": "Edukacja i system szkolny",
  "vestmannaeyjar.E.list.1.interests.1": "Usługi dla osób starszych",
  "vestmannaeyjar.E.list.1.interests.2": "Wodociągi i inwestycje infrastrukturalne",
  "vestmannaeyjar.E.list.1.interests.3": "Rozwój portu i turystyka",
  "vestmannaeyjar.E.list.1.occupation": "Nauczycielka i licencjonowana pośredniczka w obrocie nieruchomościami i statkami",
  "vestmannaeyjar.E.list.2.occupation": "Nauczyciel",
  "vestmannaeyjar.E.tagline": "Eyjalistinn — słuchamy mieszkańców wysp",
  "vestmannaeyjar.M.agenda.0.text": "Poprawa połączeń z lądem stałym — Landeyjahöfn musi działać lepiej.",
  "vestmannaeyjar.M.agenda.0.title": "Landeyjahöfn",
  "vestmannaeyjar.M.agenda.1.text": "Planowa rozbudowa i rozwój miasta na wyspie.",
  "vestmannaeyjar.M.agenda.1.title": "Planowanie przestrzenne",
  "vestmannaeyjar.M.agenda.2.text": "Zrównoważone wykorzystanie zasobów i ochrona środowiska na wyspach.",
  "vestmannaeyjar.M.agenda.2.title": "Ochrona środowiska",
  "vestmannaeyjar.M.agenda.3.text": "Efektywne funkcjonowanie gminy i odpowiedzialne zarządzanie finansami.",
  "vestmannaeyjar.M.agenda.3.title": "Zarządzanie",
  "vestmannaeyjar.M.agenda.4.text": "„Małe Monako” — Vestmannaeyjar jako pożądany kierunek.",
  "vestmannaeyjar.M.agenda.4.title": "Wizja przyszłości",
  "vestmannaeyjar.M.list.1.bio": "Jón Þór Guðjónsson pracuje w dziale informatycznym Vestmannaeyjabær i stoi na czele listy Miðflokkurinn w Vestmannaeyjar w 2026 roku — po raz pierwszy partia rozważa udział w radzie miejskiej wysp. Wypowiadał się na temat kwestii transportowych na wyspach, zwłaszcza powtarzających się zakłóceń w połączeniach przez Landeyjahöfn.",
  "vestmannaeyjar.M.list.1.interests.0": "Transport i Landeyjahöfn",
  "vestmannaeyjar.M.list.1.interests.1": "Technologia i telekomunikacja",
  "vestmannaeyjar.M.list.1.interests.2": "Usługi dla mieszkańców",
  "vestmannaeyjar.M.list.1.interests.3": "Odpowiedzialne zarządzanie finansami",
  "vestmannaeyjar.M.list.1.occupation": "Pracownik działu informatycznego Vestmannaeyjabær",
  "vestmannaeyjar.M.list.2.occupation": "Kandydat",
  "vestmannaeyjar.M.list.4.occupation": "Kierownik ds. rekreacji i aktywizacji",
  "vestmannaeyjar.M.tagline": "Miðflokkurinn w Vestmannaeyjum — wartości i służba",
  "vesturbyggd.NYS.agenda.0.text": "Wzmacnianie innowacyjności i zróżnicowanego życia gospodarczego na Vestfjörðum.",
